import java.io.*;
import java.util.*;

public class XSSSecureCode {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.println("Enter your name: ");
        String userName = scanner.nextLine();

        // Sanitize and escape user input to prevent XSS
        userName = sanitizeInput(userName);

        System.out.println("Hello, " + userName + "!"); // Safe output

        scanner.close();
    }

    private static String sanitizeInput(String input) {
        // Implement proper input sanitization here
        // For demonstration purposes, we will use a simple method to escape HTML special characters

        return input.replaceAll("&", "&amp;")
                    .replaceAll("<", "&lt;")
                    .replaceAll(">", "&gt;")
                    .replaceAll("\"", "&quot;")
                    .replaceAll("'", "&#39;");
    }
}

